definition.script:
pipeline {
agent any

```
environment {
    DOCKER_IMAGE = "sgyanendra1/school-erp-api"
    IMAGE_TAG = "${BUILD_NUMBER}"
    HELM_RELEASE = "school-erp-api"
    NAMESPACE = "default"
}

stages {

    stage('Checkout Code') {
        steps {
            git branch: 'main', url: 'https://github.com/gyanendrasingh08/school-erp-api.git'
        }
    }

    stage('Build Docker Image') {
        steps {
            script {
                docker.build("${DOCKER_IMAGE}:${IMAGE_TAG}")
            }
        }
    }

    stage('Push to Docker Hub') {
        steps {
            script {
                docker.withRegistry('', 'dockerhub-gyan-creds') {
                    docker.image("${DOCKER_IMAGE}:${IMAGE_TAG}").push()
                    docker.image("${DOCKER_IMAGE}:${IMAGE_TAG}").push("latest")
                }
            }
        }
    }

    stage('Deploy to k3s via Helm') {
        steps {
            withCredentials([file(credentialsId: 'kubeconfig', variable: 'KUBECONFIG')]) {
                sh """
                helm upgrade --install ${HELM_RELEASE} ./helm \
                  --namespace ${NAMESPACE} \
                  --create-namespace \
                  --set image.repository=${DOCKER_IMAGE} \
                  --set image.tag=${IMAGE_TAG}
                """
            }
        }
    }
}

post {
    success {
        echo "✅ Deployment successful!"
    }
    failure {
        echo "❌ Deployment failed!"
    }
}
```

}
